.channel-item {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    padding: 8px 12px;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.12);
    border-left-color: #5865f2;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #dcddde;
    flex: 1;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-desc {
    width: 100%;
    font-size: 0.75rem;
    color: #8e9297;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background-color: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    background: #40444b;
    border-top: 1px solid #2f3136;
    align-items: flex-end;
}

.message-input textarea {
    flex: 1;
    background: #40444b;
    border: 1px solid #72767d;
    border-radius: 6px;
    color: #dcddde;
    padding: 8px 12px;
    font-size: 0.9rem;
    resize: none;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #5865f2;
}

.send-btn {
    background: #5865f2;
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 16px;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    transition: background-color 0.15s;
}

.send-btn:hover:not(:disabled) {
    background: #4752c4;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
