arguments.file_text:
.message-bubble {
    padding: 6px 16px;
    position: relative;
    transition: background-color 0.1s;
}

.message-bubble.hovered {
    background-color: #32353b;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 600;
    color: #fff;
    font-size: 0.95rem;
}

.timestamp {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    color: #dcddde;
    font-size: 0.9rem;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-link {
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 4px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
}

.action-btn {
    background: transparent;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 3px;
    line-height: 1;
    transition: background-color 0.1s;
}

.action-btn:hover {
    background: #40444b;
}

.react-wrapper {
    position: relative;
}

.channel-sidebar {
    width: 240px;
    min-width: 240px;
    background: #2f3136;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #202225;
    overflow: hidden;
}

.sidebar-header {
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.02em;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #36393f;
    min-width: 0;
    overflow: hidden;
}

.area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
    background: #36393f;
    display: flex;
    align-items: baseline;
    gap: 12px;
    min-height: 48px;
}

.area-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
    white-space: nowrap;
}

.header-desc {
    font-size: 0.85rem;
    color: #8e9297;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 0;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.loading-indicator {
    text-align: center;
    color: #72767d;
    font-size: 0.85rem;
    padding: 12px;
}

.thread-panel {
    width: 340px;
    min-width: 340px;
    background: #2f3136;
    border-left: 1px solid #202225;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
}

.close-btn {
    background: transparent;
    border: none;
    color: #8e9297;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.1s, color 0.1s;
}

.close-btn:hover {
    background: #40444b;
    color: #fff;
}

.thread-root {
    padding: 12px 16px;
    background: #36393f;
    border-bottom: 1px solid #202225;
}

.root-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.9rem;
    margin-bottom: 4px;
}

.root-content {
    color: #dcddde;
    font-size: 0.85rem;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-divider {
    padding: 8px 16px;
    border-bottom: 1px solid #40444b;
}

.thread-divider span {
    font-size: 0.75rem;
    color: #72767d;
    font-weight: 600;
    text-transform: uppercase;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-reply {
    padding: 6px 16px;
    transition: background-color 0.1s;
