{"file_text": "<div class="message-area">
    <div class="area-header">
        @if (ActiveChannel is not null)
        {
            <h2># @ActiveChannel.Name</h2>
            <span class="header-desc">@ActiveChannel.Description</span>
        }
    </div>

    <div class="message-list" @ref="_messageListRef">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages...</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageBubble Message="msg"
                           ThreadReplyCount="GetReplyCount(msg.Id)"
                           OnOpenThread="OnOpenThread"
                           OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ActiveChannel?.Name ?? "channel"}")"
                  ButtonText="Send"
                  OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter] public Channel? ActiveChannel { get; set; }
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnScrolledToTop { get; set; }

    [Inject] private IJSRuntime JS { get; set; } = default!;

    private ElementReference _messageListRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<MessageArea>? _dotNetRef;
    private bool _shouldScrollToBottom = true;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/chat-scroll.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("observeScrollTop", _messageListRef, _dotNetRef);
        }

        if (_shouldScrollToBottom)
        {
            _shouldScrollToBottom = false;
            if (_module is not null)
            {
                await _module.InvokeVoidAsync("scrollToBottom", _messageListRef);
            }
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        await OnScrolledToTop_Callback();
    }

    private async Task OnScrolledToTop_Callback()
    {
        await OnScrolledToTop.InvokeAsync();
    }

    public void RequestScrollToBottom() => _shouldScrollToBottom = true;

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.GetValueOrDefault(messageId, 0);

    public async ValueTask DisposeAsync()
    {
        _dotNetRef?.Dispose();
        if (_module is not null) await _module.DisposeAsync();
    }

    public async Task<double> GetScrollHeight()
    {
        if (_module is null) return 0;
        return await _module.InvokeAsync<double>("getScrollHeight", _messageListRef);
    }

    public async Task PreserveScroll(double previousHeight)
    {
        if (_module is not null)
            await _module.InvokeVoidAsync("preserveScrollPosition", _messageListRef, previousHeight);
    }
}
