    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 4px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
}

.action-btn {
    background: transparent;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 3px;
    line-height: 1;
    transition: background-color 0.1s;
}

.action-btn:hover {
    background: #40444b;
}

.react-wrapper {
    position: relative;
}

