.thread-panel {
    width: 340px;
    min-width: 340px;
    background: #2f3136;
    border-left: 1px solid #202225;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
}

.close-btn {
    background: transparent;
    border: none;
    color: #8e9297;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.1s, color 0.1s;
}

.close-btn:hover {
    background: #40444b;
    color: #fff;
}

.thread-root {
    padding: 12px 16px;
    background: #36393f;
    border-bottom: 1px solid #202225;
}

.root-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.9rem;
    margin-bottom: 4px;
}

.root-content {
    color: #dcddde;
    font-size: 0.85rem;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-divider {
    padding: 8px 16px;
    border-bottom: 1px solid #40444b;
}

.thread-divider span {
    font-size: 0.75rem;
    color: #72767d;
    font-weight: 600;
    text-transform: uppercase;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-reply {
    padding: 6px 16px;
    transition: background-color 0.1s;
}

.thread-reply:hover {
    background: #32353b;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.85rem;
}

.reply-time {
    font-size: 0.7rem;
    color: #72767d;
}

.reply-content {
    color: #dcddde;
    font-size: 0.85rem;
    line-height: 1.3;
    white-space: pre-wrap;
    word-break: break-word;
}

