arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<ChannelSidebar Channels="_channels"
                ActiveChannelId="_activeChannelId"
                OnChannelSelected="SelectChannel" />

<MessageArea @ref="_messageArea"
             ActiveChannel="_activeChannel"
             Messages="_messages"
             ThreadReplyCounts="_threadReplyCounts"
             IsLoadingMore="_isLoadingMore"
             OnOpenThread="OpenThread"
             OnReact="HandleReaction"
             OnSendMessage="SendMessage"
             OnScrolledToTop="LoadOlderMessages" />

@if (_threadRootMessage is not null)
{
    <ThreadPanel RootMessage="_threadRootMessage"
                 Replies="_threadReplies"
                 OnSendReply="SendThreadReply"
                 OnClose="CloseThread" />
}

@code {
    [Inject] private IChatService ChatService { get; set; } = default!;

    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<Message> _threadReplies = [];
    private Dictionary<int, int> _threadReplyCounts = [];

    private int? _activeChannelId;
    private Channel? _activeChannel;

    private Message? _threadRootMessage;
    private int? _openThreadRootId;

    private bool _isLoadingMore;
    private bool _hasMoreMessages = true;
    private const int PageSize = 50;

    private MessageArea? _messageArea;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        if (_activeChannelId == channelId) return;

        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _threadReplyCounts = [];
        _hasMoreMessages = true;

        CloseThread();

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        ComputeThreadReplyCounts();

        await ChatService.MarkChannelReadAsync(channelId);
        RefreshChannelUnread(channelId);

        _messageArea?.RequestScrollToBottom();
    }

    private async Task LoadOlderMessages()
    {
        if (_isLoadingMore || !_hasMoreMessages || _activeChannelId is null) return;

        _isLoadingMore = true;
        StateHasChanged();

        double previousHeight = 0;
        if (_messageArea is not null)
            previousHeight = await _messageArea.GetScrollHeight();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, PageSize);
        if (older.Count < PageSize) _hasMoreMessages = false;
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            ComputeThreadReplyCounts();
        }

        _isLoadingMore = false;
        StateHasChanged();

        // Preserve scroll position after prepending older messages
        if (_messageArea is not null && previousHeight > 0)
        {
            await Task.Yield();
            await _messageArea.PreserveScroll(previousHeight);
        }
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannelId is null) return;

        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, content, null);
        _messages.Add(msg);
        _messageArea?.RequestScrollToBottom();
    }

    private async Task OpenThread(int rootMessageId)
    {
        _openThreadRootId = rootMessageId;
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);

        var replies = await ChatService.GetThreadAsync(rootMessageId);
        _threadReplies = replies.Where(r => r.Id != rootMessageId).ToList();
    }

    private void CloseThread()
    {
        _openThreadRootId = null;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_openThreadRootId is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, content, _openThreadRootId);
        _threadReplies.Add(reply);

        // Update reply count in main view
        _threadReplyCounts[_openThreadRootId.Value] =
            _threadReplyCounts.GetValueOrDefault(_openThreadRootId.Value, 0) + 1;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic update: add or increment the reaction locally
        var msg = _messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private void ComputeThreadReplyCounts()
    {
        _threadReplyCounts = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }

    private void RefreshChannelUnread(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = _channels[idx];
            _channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_messageArea is not null)
            await _messageArea.DisposeAsync();
    }
}

::deep .chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    display: flex;
    background: #36393f;
    color: #dcddde;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
}

